SELECT eval_period_id AS evalPeriodId, eval_year AS evalYear, eval_sequence AS evalSequence, eval_type AS evalType, start_date AS startDate, end_date AS endDate, status, algorithm_version_id AS algorithmVersionId FROM evaluation_period
AND eval_year = #{year} AND status = #{status}
ORDER BY eval_year DESC, eval_sequence DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM evaluation_period

    AND eval_year = #{year}
    AND status = #{status}
